CREATE PROCEDURE sp_refresh_monthly_billing
    @year INT,
    @month INT
AS
BEGIN
    BEGIN TRY
        DELETE FROM monthly_billing WHERE year = @year AND month = @month;

        INSERT INTO monthly_billing
            (year, month, region, customer_type, meter_count, total_kw, total_mw, avg_kw, max_kw)
        SELECT YEAR(date), MONTH(date), region, customer_type,
            COUNT(DISTINCT meter_id), ROUND(SUM(daily_kw), 2),
            ROUND(SUM(daily_kw) / 1000, 4), ROUND(AVG(daily_kw), 2), ROUND(MAX(daily_kw), 2)
        FROM lh_meter_readings.dbo.silver_meters
        WHERE YEAR(date) = @year AND MONTH(date) = @month
        GROUP BY YEAR(date), MONTH(date), region, customer_type;

        UPDATE STATISTICS monthly_billing;
        ALTER MATERIALIZED VIEW mv_monthly_region_summary REBUILD;

        INSERT INTO refresh_log (procedure_name, year, month, status, completed_at)
        VALUES ('sp_refresh_monthly_billing', @year, @month, 'SUCCESS', GETDATE());
    END TRY
    BEGIN CATCH
        INSERT INTO refresh_log (procedure_name, year, month, status, error_message, completed_at)
        VALUES ('sp_refresh_monthly_billing', @year, @month, 'FAILED', ERROR_MESSAGE(), GETDATE());
        THROW;
    END CATCH
END;

